-- box-elder-development-reports-seed.sql
-- Cached ZIP-mode output of the get-address-report edge function for the Box Elder pilot.
-- PROTOTYPE ZIP: 84302 (Brigham City, Box Elder County, UT).
--
-- Prime directive (docs/development-tracker-source-of-truth.md §0): this is a verbatim
-- CACHE of what the engine returned — NOT hand-authored site data. Every one of the 64
-- rows below carries an official record_url/url (EPA ECHO registry link or a Utah PMN /
-- county / city notice URL). 0 unsourced. A ZIP with no records would seed an EMPTY (but
-- valid) report — never a fabricated one.
--
-- PROVENANCE
--   • ZIP centroid: PINNED to the `zipcodes` PyPI package v3.0.0 (bundled offline USPS
--     dataset — the same authoritative source the alerts builds pin, §12.0).
--     84302 → (41.5079, -112.0152).
--   • sites/counts: get-address-report v9 ZIP-mode response for {"zip":"84302"}, captured
--     server-side (Supabase infra egress → live EPA FRS/ECHO + Utah PMN/county/city feeds).
--   • 84302 aggregate: facilities 23 · development 41 · proposed 41 · approved 0 ·
--     open comment windows 0.
--
-- Idempotent & re-appliable (mirrors the alerts docs/*-seed.sql convention). Parked/applied
-- manually in the Supabase SQL editor. RLS ships enabled in the DDL below (public select,
-- no anon writes) — do NOT model on page_cache (which shipped RLS-disabled).
--
-- To REFRESH from the live engine instead of re-applying this snapshot (service-role only):
--   select net.http_post(
--     'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
--     body := '{"zip":"84302"}'::jsonb,
--     headers := '{"Content-Type":"application/json"}'::jsonb, timeout_milliseconds := 45000);
--   -- then upsert net._http_response.content (see docs/development-reports-cache.sql §upsert).

-- ── Table + RLS (idempotent; identical to docs/development-reports-cache.sql) ──────────
create table if not exists public.development_reports (
  zip           text primary key check (zip ~ '^\d{5}$'),
  home_lat      double precision not null,
  home_lng      double precision not null,
  counts        jsonb not null default '{}'::jsonb,
  sites         jsonb not null default '[]'::jsonb,
  paywall       boolean not null default false,
  source_vintage text,
  refreshed_at  timestamptz not null default now(),
  created_at    timestamptz not null default now()
);
alter table public.development_reports enable row level security;
do $$
begin
  if not exists (select 1 from pg_policies where schemaname='public'
     and tablename='development_reports' and policyname='development_reports_public_read') then
    create policy development_reports_public_read
      on public.development_reports for select using (true);
  end if;
end$$;

